// Levenshtein-Distanz — Inline-Implementation laut CLAUDE.md §6.6.
// Reicht für unsere Eingabe-Längen (typisch 3–25 Zeichen) ohne Package.
//
// Algorithmus: dynamische Programmierung mit zwei Reihen (O(min(m,n)) Memory).

export function levenshtein(a: string, b: string): number {
  if (a === b) return 0
  if (!a.length) return b.length
  if (!b.length) return a.length

  // Stelle sicher, dass a die kürzere Zeichenkette ist (spart Speicher)
  if (a.length > b.length) [a, b] = [b, a]

  let prev = new Array(a.length + 1)
  let curr = new Array(a.length + 1)

  for (let i = 0; i <= a.length; i++) prev[i] = i

  for (let j = 1; j <= b.length; j++) {
    curr[0] = j
    for (let i = 1; i <= a.length; i++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1
      curr[i] = Math.min(
        curr[i - 1] + 1,        // insert
        prev[i] + 1,            // delete
        prev[i - 1] + cost      // substitute
      )
    }
    ;[prev, curr] = [curr, prev]
  }

  return prev[a.length]
}

/**
 * Normalisiert für den Vergleich: lowercase + trim + collapse whitespace.
 * Diakritika bleiben relevant — "fáj" vs "faj" bleibt 1 Distanz, das ist
 * pädagogisch erwünscht.
 */
export function normalizeForCompare(s: string): string {
  return s.toLowerCase().trim().replace(/\s+/g, ' ')
}
